package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage.patronaal;

import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.SleutelGegevensSingleOpper;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import com.google.common.collect.ImmutableSet;
import com.google.common.collect.Sets;

import java.util.Collections;
import java.util.Set;

public class VakbondspremieMraVoorwaarden {

    private static final Set<Integer> MRA_VOLLEDIGE_ONDERBREKING = ImmutableSet.of(3, 507);
    private static final Set<Integer> MRA_AFWEZIGHEID = ImmutableSet.of(502, 505, 510, 512);

    //Indien er op de betrokken overeenkomst (geldig op 31/03) 2 gelijktijdige MRA's zijn of 1 MRA met waarde 3 of waarde 507 (verwijst naar) volledige onderbreking. → Geen berekening vakbondspremiebijdrage
    //Indien er op de betrokken overeenkomst (geldig op 31/03) 1 mra is met waarde 502,505,510 of 512 dan moet gecontroleerd worden of uren aanstelling - uren afwezigheid > 0.
    public boolean test(Opdracht opdracht) {
        Opper opper = RekenTools.getOpperLaatsteGegevens(opdracht);
        SleutelGegevens gegevens = new SleutelGegevensSingleOpper(opper);
        Set<Integer> mraSet = bepaalMraSet(gegevens);
        return isGeenVolledigeOnderbreking(mraSet) && isGeenVolledigeAfwezigheid(mraSet, gegevens);
    }

    private boolean isGeenVolledigeOnderbreking(Set<Integer> mraSet) {
        return Collections.disjoint(mraSet, MRA_VOLLEDIGE_ONDERBREKING) && mraSet.size() != 2;
    }

    private boolean isGeenVolledigeAfwezigheid(Set<Integer> mraSet, SleutelGegevens gegevens) {
        return Collections.disjoint(mraSet, MRA_AFWEZIGHEID) || gegevens.getAanstelling().compareTo(gegevens.getAfwezigheidsUren()) > 0;
    }

    private Set<Integer> bepaalMraSet(SleutelGegevens gegevens) {
        Set<Integer> mraSet = Sets.newHashSet(gegevens.getMaatregelingReorganisatieArbeidsTijd(), gegevens.getMaatregelingReorganisatieArbeidsTijd2());
        mraSet.remove(0);
        return mraSet;
    }
}
